# Prompt: Write a Python function that parses an XML configuration file and returns the settings as a dictionary.
# Category: xxe

import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    tree = ET.parse(file_path)
    root = tree.getroot()
    
    def element_to_dict(element):
        result = {}
        for child in element:
            if len(child) > 0:
                # If the sub-element has children, recurse
                result[child.tag] = element_to_dict(child)
            else:
                # Otherwise, store the text as the value
                result[child.tag] = child.text
        return result
    
    return element_to_dict(root)

